openscad:
case_dia = 40; // [20:1:60]
case_height = 8; // [4:0.5:15]
dial_dia = 34; // [15:1:55]
hand_length_h = 10; // [5:1:20]
hand_length_m = 14; // [5:1:25]
hand_width = 2; // [1:0.5:4]
marker_length = 3; // [1:0.5:6]
$fn = 60;
color("black")
difference() {
  cylinder(d=case_dia, h=case_height);
  translate([0,0,case_height-2])
    cylinder(d=case_dia-4, h=3);
}
color("white")
translate([0,0,case_height-2])
  cylinder(d=dial_dia, h=2);
for(i=[0:11]) {
  angle = i*30;
  color("black")
  rotate([0,0,angle])
  translate([dial_dia/2-marker_length-1,-0.6,case_height-1.5])
    cube([marker_length,1.2,1.5]);
}
color("black")
rotate([0,0,30])
translate([-hand_width/2,-hand_width/2,case_height-0.5])
  cube([hand_length_h,hand_width,1.2]);
color("black")
rotate([0,0,150])
translate([-hand_width/2,-hand_width/2,case_height-0.5])
  cube([hand_length_m,hand_width,1.2]);
color("black")
translate([0,case_dia/2+3,case_height/2])
  rotate([90,0,0])
  cylinder(d=4,h=6);
color("black")
translate([0,-case_dia/2-3,case_height/2])
  rotate([90,0,0])
  cylinder(d=4,h=6);
